```Go [sol1-Go]
func pairSum(head *ListNode) int {
    slow := head
    fast := head.Next
    for fast.Next != nil {
        slow = slow.Next
        fast = fast.Next.Next
    }

    // 反转后半部分链表
    last := slow.Next
    for last.Next != nil {
        cur := last.Next
        last.Next = cur.Next
        cur.Next = slow.Next
        slow.Next = cur
    }

    ans := 0
    x := head
    y := slow.Next
    for y != nil {
        if x.Val + y.Val > ans {
            ans = x.Val + y.Val
        }
        x = x.Next
        y = y.Next
    }
    return ans
}
```

```C [sol1-C]
int pairSum(struct ListNode* head) {
    struct ListNode* slow = head;
    struct ListNode* fast = head->next;
    while (fast->next) {
        slow = slow->next;
        fast = fast->next->next;
    }

    // 反转后半部分链表
    struct ListNode* last = slow->next;
    while (last->next) {
        struct ListNode* cur = last->next;
        last->next = cur->next;
        cur->next = slow->next;
        slow->next = cur;
    }

    int ans = 0;
    struct ListNode* x = head;
    struct ListNode* y = slow->next;
    while (y) {
        int sum = x->val + y->val;
        if (sum > ans) {
            ans = sum;
        }
        x = x->next;
        y = y->next;
    }
    return ans;
}
